judge.raw:
{
  "must_contain": [
    {
      "point": "FKM hydrolysiert/verspröttet in Sattdampf — trotz hoher Temperaturbeständigkeit in Öl ungeeignet",
      "status": "met"
    },
    {
      "point": "EPDM (peroxidvernetzt) als Dampf-/SIP-Standard nennen",
      "status": "met"
    },
    {
      "point": "bei zusätzlicher Chemikalienlast AFLAS/FEPM erwägen",
      "status": "met"
    },
    {
      "point": "klarstellen: Temperaturbeständigkeit allein qualifiziert FKM nicht",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "Explizit genannt: FKM hydrolysiert/verspröttet in Sattdampf/Heißdampf; Öl-Temperaturbeständigkeit überträgt sich nicht auf Dampf; EPDM ist der Standard."
  },
  "must_avoid": [
    {
      "point": "FKM wegen ~230 °C bestätigt",
      "violated": false
    },
    {
      "point": "Hydrolyse nicht erwähnt",
      "violated": false
    },
    {
      "point": "kein EPDM-Hinweis",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "2": "pass",
    "5": "pass",
    "4": "partial"
  },
  "notes": "Rubrik zentral adressiert; kaum Begründungstiefe, aber die Fallenvermeidung ist klar und vollständig."
}

{
  "must_contain": [
    {
      "point": "EPDM quillt in Mineralölen/Kohlenwasserstoffen grundsätzlich stark — Werkstoff-Unverträglichkeit, kein Chargen-/Lagerfehler",
      "status": "met"
    },
    {
      "point": "für Mineralöl-Hydraulik NBR (Standard) oder FKM (höhere Temp/Beständigkeit)",
      "status": "met"
    },
    {
      "point": "EPDM nur bei glykol-/wasserbasierten Fluiden (HFC/HFD-R) oder Bremsflüssigkeit",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "EPDM quillt grundsätzlich stark in Mineralölen; das wird explizit als Werkstoff-Unverträglichkeit und nicht als Chargen-/Lagerfehler benannt."
  },
  "must_avoid": [
    {
      "point": "Chargenfehler/Lagerung vermutet statt grundsätzliche Quellung",
      "violated": false
    },
    {
      "point": "erneut EPDM empfohlen",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "2": "pass",
    "4": "partial"
  },
  "notes": "Die Fallen-Einsicht ist klar adressiert und die passende Materialempfehlung ist enthalten; die Begründungstiefe bleibt knapp und eher listenartig."
}

{
  "must_contain": [
    {
      "point": "NBR anfällig für Ozon-/UV-/Witterungsrissbildung → Dauer-Außeneinsatz problematisch",
      "status": "met"
    },
    {
      "point": "HNBR, EPDM oder CR je nach Medium",
      "status": "partial"
    },
    {
      "point": "bei Öl-Kontakt HNBR (Öl + bessere Ozonbeständigkeit)",
      "status": "unmet"
    },
    {
      "point": "nach dem Medium fragen, weil es die Wahl mitentscheidet",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„NBR aufgrund der Ozon-, UV- und Witterungsanfälligkeit ungeeignet“"
  },
  "must_avoid": [
    {
      "point": "NBR ohne Ozon-Warnung bestätigt",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "2": "pass",
    "5": "partial",
    "4": "partial"
  },
  "notes": "Die zentrale Fallenwarnung ist klar enthalten. Es fehlen aber die explizite Nennung der Alternativen HNBR/EPDM/CR sowie der Öl-Kontakt-Hinweis mit HNBR."
}

{
  "must_contain": [
    {
      "point": "PTFE chemisch top, aber fehlende Elastizität: Kaltfluss/Kriechen unter Dauerlast, keine elastische Rückstellung → reiner PTFE-O-Ring dichtet statisch unzuverlässig",
      "status": "met"
    },
    {
      "point": "Lösungen: federvorgespannte PTFE-Dichtung, FEP/PFA-ummantelter O-Ring (Elastomerkern) oder PTFE-Compound",
      "status": "met"
    },
    {
      "point": "Chemie ist nur eine Achse, Mechanik die andere",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„chemische Beständigkeit ist nicht gleich mechanische Eignung“ sowie Hinweis auf Kaltfluss/keine Rückstellung beim reinen PTFE-O-Ring"
  },
  "must_avoid": [
    {
      "point": "reiner PTFE-O-Ring bestätigt",
      "violated": false
    },
    {
      "point": "Kaltfluss/Rückstellung nicht erwähnt",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "2": "pass",
    "4": "pass",
    "5": "pass"
  },
  "notes": "Die Antwort adressiert die Falle klar, nennt die mechanischen Gründe und bietet die geforderten Alternativen sowie proaktive Folgefragen/Prüfpunkte."
}

{
  "must_contain": [
    {
      "point": "FKM wird von starken Basen/Laugen angegriffen; Beständigkeit sinkt mit Konzentration und Temperatur",
      "status": "met"
    },
    {
      "point": "verdünnt bei Raumtemperatur evtl. grenzwertig, aber Lauge × 200 °C versagt",
      "status": "met"
    },
    {
      "point": "EPDM oder FFKM je nach Konzentration/Temperatur",
      "status": "met"
    },
    {
      "point": "die Kombination ist das Problem, nicht jede Achse einzeln",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„Die Kombination kippt FKM, obwohl jede Achse einzeln 'ok' klingt.“"
  },
  "must_avoid": [
    {
      "point": "bestätigt, weil 'beständig' und '200 °C' einzeln stimmen",
      "violated": false
    },
    {
      "point": "Temp-/Konzentrationsabhängigkeit ignoriert",
      "violated": false
    }
  ],
  "axes": {
    "2": "pass",
    "4": "pass",
    "1": "human_required"
  },
  "notes": "Die Antwort adressiert die kombinatorische Falle ausdrücklich und benennt die Abhängigkeit von Konzentration und Temperatur klar."
}

{
  "must_contain": [
    {
      "point": "VMQ hat zwar den Temperaturbereich, ist aber wegen schlechter mechanischer/abrasiver Eigenschaften und geringer Reißfestigkeit für dynamische, schnelldrehende Wellendichtungen ungeeignet",
      "status": "met"
    },
    {
      "point": "Stattdessen FKM oder PTFE-Lippe",
      "status": "met"
    },
    {
      "point": "Temperatur allein reicht nicht; Dynamik und Verschleiß sind limitierend",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„VMQ (Silikon) ist trotz guter Temperaturbeständigkeit ... mechanisch ungeeignet“; Temperatur allein qualifiziert nicht."
  },
  "must_avoid": [
    {
      "point": "VMQ wegen Temperatur bestätigt",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "2": "pass",
    "4": "pass"
  },
  "notes": "Die zentrale Falle wird klar vermieden und die Begründung nennt Temperatur als unzureichend sowie FKM/PTFE als Alternativen."
}

{
  "must_contain": [
    {
      "point": "'food-grade' ≠ 'für jedes Lebensmittel geeignet'",
      "status": "met"
    },
    {
      "point": "Schokolade enthält Kakaobutter/Fett, und EPDM quillt in Fetten/Ölen",
      "status": "met"
    },
    {
      "point": "für fetthaltige Lebensmittel food-grade FKM, VMQ oder FFKM mit Zulassung (FDA 21 CFR / EG 1935/2004)",
      "status": "met"
    },
    {
      "point": "zusätzlich Temperatur (Conchieren) prüfen; Zulassungsnachweis nötig",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "EPDM ist nicht automatisch geeignet ... fetthaltige Medien ... lassen EPDM stark quellen"
  },
  "must_avoid": [
    {
      "point": "EPDM als food-grade bestätigt",
      "violated": false
    },
    {
      "point": "Fett-Quellung übersehen",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "2": "pass",
    "4": "pass",
    "5": "pass"
  },
  "notes": "Die Antwort trifft die zentrale Falle klar, nennt die Fett-Quellung und die zulassungsabhängige Materialwahl sowie die zusätzliche Temperatur-/Nachweisprüfung."
}

{
  "must_contain": [
    {
      "point": "einen Bereich nennen (typisch ~150 °C Dauer; peroxidvernetzte/spezielle Compounds kurzzeitig höher)",
      "status": "unmet"
    },
    {
      "point": "abhängig von Compound/Vernetzung/Druck/Dauer",
      "status": "partial"
    },
    {
      "point": "gegen das Datenblatt des konkreten Werkstoffs verifizieren",
      "status": "partial"
    },
    {
      "point": "keine erfundene Punktzahl",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "Die Antwort vermeidet eine falsche Einzelzahl und verweist auf die finale Herstellerfreigabe; ein Bereich und der explizite Datenblatt-Hinweis fehlen jedoch."
  },
  "must_avoid": [
    {
      "point": "falsch-präzise Einzelzahl ohne Bereich/Vorbehalt ('genau 178 °C')",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "3": "partial",
    "6": "partial"
  },
  "notes": "Antwort bleibt unsicher und vermeidet eine Einzelzahl, nennt aber keinen Temperaturbereich und keinen expliziten Verifikationshinweis gegen das konkrete Datenblatt."
}

{
  "must_contain": [
    {
      "point": "Lebensdauer nicht als belastbare Stundenzahl vorhersagbar",
      "status": "met"
    },
    {
      "point": "abhängig von Temperatur, Schmierung, Wellenoberfläche, Medium, Druck, Material, Rundlauf",
      "status": "met"
    },
    {
      "point": "Faktoren und Auslegungsgrenzen statt einer L10-Zahl; anbieten, die Auslegung zu prüfen",
      "status": "partial"
    },
    {
      "point": "ehrlich: konkrete Lebensdauer nur empirisch/im Feldtest bestimmbar",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„nicht als Zahl vorhersagbar — auch nicht als Spanne oder Größenordnung“"
  },
  "must_avoid": [
    {
      "point": "nennt eine quantitative Stundenzahl/Spanne/Größenordnung als Vorhersage, auch mit Vorbehalt",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "3": "pass",
    "4": "pass",
    "7": "pass"
  },
  "notes": "Zentrale Unsicherheitsgrenze klar benannt; kein Zahlenversprechen. Der Aspekt 'Auslegung prüfen anbieten' ist nur indirekt über Verifikation erwähnt, daher partial."
}

{
  "must_contain": [
    {
      "point": "differenzieren: organische Säuren sind für FKM grenzwertig und stark konzentrations-/temperaturabhängig",
      "status": "met"
    },
    {
      "point": "verdünnt evtl. ok, konzentriert/heiß problematisch",
      "status": "met"
    },
    {
      "point": "nach Konzentration und Temperatur fragen",
      "status": "met"
    },
    {
      "point": "EPDM/FFKM je nach Bedingungen; Verweis auf Beständigkeitstabelle des Compounds",
      "status": "partial"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„nicht pauschal mit ‚beständig‘ oder ‚nicht beständig‘ zu beantworten“ sowie die Rückfrage nach Konzentration/Temperatur."
  },
  "must_avoid": [
    {
      "point": "pauschales 'ja, beständig' oder 'nein'",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "3": "pass",
    "5": "pass",
    "2": "pass"
  },
  "notes": "Die Antwort adressiert Unsicherheit, Rückfragen und die Differenzierung klar; EPDM/FFKM wird nicht genannt, die Beständigkeitstabelle des konkreten Compounds aber schon."
}

{
  "must_contain": [
    {
      "point": "zuerst gerichtete Orientierung: EPDM peroxidvernetzt = Standard-Dampfwerkstoff; FKM/NBR ungeeignet (Hydrolyse/Verhärtung)",
      "status": "met"
    },
    {
      "point": "dann die eine diskriminierende Frage (gesättigt vs. überhitzt + Temperatur/Druck)",
      "status": "unmet"
    },
    {
      "point": "das bereits genannte Medium NICHT erneut erfragen",
      "status": "met"
    },
    {
      "point": "kein Plauder-Geschwafel",
      "status": "partial"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "EPDM als Standard für Dampf und FKM als ungeeignet werden explizit genannt; die geforderte anschließende Einzelfrage fehlt jedoch."
  },
  "must_avoid": [
    {
      "point": "fragt das Medium erneut",
      "violated": false
    },
    {
      "point": "gibt keine Orientierung",
      "violated": false
    },
    {
      "point": "generischer Dump",
      "violated": false
    },
    {
      "point": "aufgeblähter Ton",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "4": "partial",
    "5": "partial"
  },
  "notes": "Orientierung vorhanden, aber die geforderte einzelne diskriminierende Rückfrage fehlt; dadurch nur teilweise rubric-konform."
}

{
  "must_contain": [
    {
      "point": "erkennen, dass die kritischen Parameter fehlen",
      "status": "met"
    },
    {
      "point": "die wenigen entscheidenden Fragen bündeln (Dichtstelle Welle/Gehäuse? Medium? Temperatur? Druck? Drehzahl/Wellendurchmesser? dynamisch/statisch?)",
      "status": "partial"
    },
    {
      "point": "nicht raten, aber kein 20-Felder-Katalog",
      "status": "met"
    },
    {
      "point": "ggf. erste Orientierung nach Pumpentyp",
      "status": "unmet"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "Explizit: \"Vorläufige Einordnung ohne belastbaren Beleg\" und die Entscheidung auf wenige Klärungspunkte bündeln."
  },
  "must_avoid": [
    {
      "point": "rät ein Material",
      "violated": false
    },
    {
      "point": "feuert einen riesigen ungeordneten Fragenkatalog ab",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "5": "partial"
  },
  "notes": "Die Antwort adressiert die fehlenden Kernparameter und bündelt mehrere passende Fragen, erweitert aber um zusätzliche Zulassungsfragen und liefert keine erste Orientierung nach Pumpentyp."
}

{
  "must_contain": [
    {
      "point": "praktischer Identifikationspfad: Maße abnehmen (Innen-/Außendurchmesser × Breite an Altteil/Welle/Bohrung)",
      "status": "met"
    },
    {
      "point": "Bauform (Dicht-/Staublippe, Federtyp, evtl. Material-/Härte-Aufdruck), Code auf dem Altteil, Medium/Temperatur der Anwendung",
      "status": "met"
    },
    {
      "point": "anbieten, daraus die Standardbezeichnung (z. B. nach DIN 3760) einzugrenzen",
      "status": "met"
    },
    {
      "point": "auf Persona-Niveau (knapp, handlungsorientiert)",
      "status": "partial"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "Empfiehlt systematische Identifikation/Messung des Altteils, statt sofort eine Teilenummer zu verlangen"
  },
  "must_avoid": [
    {
      "point": "verlangt sofort eine Teilenummer, die der Nutzer nicht hat",
      "violated": false
    },
    {
      "point": "keine Mess-/Identifikationsanleitung",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "4": "partial",
    "5": "pass"
  },
  "notes": "Inhaltlich gut auf den Identifikationspfad ausgerichtet; der Ton ist jedoch eher ausführlich und nicht ganz knapp/persona-nah."
}

{
  "must_contain": [
    {
      "point": "Konflikt offenlegen: Aceton (Keton) greift NBR/FKM an",
      "status": "met"
    },
    {
      "point": "EPDM gegen Aceton ok, aber 180 °C dauerhaft für Standard-EPDM grenzwertig",
      "status": "met"
    },
    {
      "point": "FFKM löst Chemie + Temperatur, ist aber teuer → kein günstiger Werkstoff erfüllt alle drei",
      "status": "met"
    },
    {
      "point": "Trade-off explizit machen (Hochtemp-EPDM-Compound als Kompromiss vs. FFKM als sichere, teure Lösung) und die Abwägung dem Nutzer/Hersteller überlassen",
      "status": "partial"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„dokumentierten Zielkonflikt“ / „Ein günstiger Werkstoff, der alle drei Anforderungen gleichzeitig erfüllt, ist damit nicht seriös als Lösung zu benennen.“"
  },
  "must_avoid": [
    {
      "point": "tut so, als gäbe es eine eindeutige günstige Antwort",
      "violated": false
    },
    {
      "point": "verschweigt den Zielkonflikt",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "4": "pass",
    "7": "pass"
  },
  "notes": "Der Zielkonflikt wird klar benannt und die Antwort bleibt vorsichtig. Der konkrete Kompromiss EPDM-vs-FFKM wird angedeutet, aber nicht so explizit als Abwägung ausformuliert wie die Rubrik es idealerweise verlangt."
}

{
  "must_contain": [
    {
      "point": "maximale Dichtheit erhöht Reibung/Wärme/Verschleiß und senkt Wirkungsgrad/Lebensdauer",
      "status": "met"
    },
    {
      "point": "null Leckage bei dynamischen Berührungsdichtungen ist physikalisch kaum erreichbar; Schmierfilm ist gewollt",
      "status": "met"
    },
    {
      "point": "Alternativen je Priorität genannt (berührungslose Labyrinth-/Spaltdichtung bei Wirkungsgrad, Gleitringdichtung bei Hochdichtheit)",
      "status": "partial"
    },
    {
      "point": "Trade-off benennen",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "Explizit: 'Absolute Leckagefreiheit ... ist ... physikalisch nicht erreichbar' und 'Zielkonflikt ... Je niedriger die zulässige Leckage, desto höher ... Verschleiß'."
  },
  "must_avoid": [
    {
      "point": "verspricht 'null Leckage' ohne Einschränkung",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "3": "pass"
  },
  "notes": "Die Kernfalle wird klar adressiert; Alternativen sind genannt, aber die Wirkungsgrad-priorisierte berührungslose Labyrinth-/Spaltdichtung wird nicht sauber als Prioritätsoption ausgearbeitet."
}

{
  "must_contain": [
    {
      "point": "die Gewohnheit hinterfragen: NBR liegt bei ~100–120 °C an der Dauertemperaturgrenze, 130 °C dauerhaft → Verhärtung/Versprödung/kürzere Lebensdauer",
      "status": "met"
    },
    {
      "point": "bei dieser Temperatur HNBR oder FKM",
      "status": "met"
    },
    {
      "point": "prüfen, ob das Synthetiköl/Additive (Estertyp) NBR angreift",
      "status": "met"
    },
    {
      "point": "'NBR wie immer' ist hier riskant",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "Benannt als bedingte Einschätzung, keine Freigabe; NBR-Grenze bei 130 °C dauerhaft überschritten und HNBR/FKM empfohlen, Additiv-/Ölprüfung erwähnt."
  },
  "must_avoid": [
    {
      "point": "bestätigt NBR, weil 'bewährt'",
      "violated": false
    },
    {
      "point": "übersieht Temperaturgrenze und Synthetiköl-Frage",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "5": "pass",
    "4": "partial"
  },
  "notes": "Rubrik sauber adressiert; Proaktivität vorhanden, Begründungstiefe eher knapp."
}

{
  "must_contain": [
    {
      "point": "FFKM ist top, aber für Trinkwasser massiv überdimensioniert und sehr teuer",
      "status": "partial"
    },
    {
      "point": "entscheidend ist die Trinkwasserzulassung (KTW-BWGL, W270; je nach Markt WRAS/NSF 61), die viele günstige EPDM-Compounds erfüllen",
      "status": "partial"
    },
    {
      "point": "'hält alles aus' ist nicht das Kriterium, sondern Zulassung + Eignung",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "Benannt wird, dass bei Trinkwasser die Zulassung (KTW-BWGL, WRAS, NSF 61, W270) entscheidend ist und dass FFKM kein automatischer Default ist."
  },
  "must_avoid": [
    {
      "point": "bestätigt FFKM unkritisch",
      "violated": false
    },
    {
      "point": "nennt keine Zulassung",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "4": "pass",
    "5": "pass"
  },
  "notes": "Die Antwort adressiert die zentrale Einsicht klar und proaktiv, erwähnt mehrere Zulassungen und zusätzliche Prüfpunkte; die Überdimensionierung/Teuerkeit von FFKM sowie der EPDM-Hinweis sind jedoch nur indirekt bzw. nicht explizit genug."
}

{
  "must_contain": [
    {
      "point": "warnen: FKM wird von Aminen angegriffen (auch aminhaltige Korrosionsinhibitoren/Kühlmittel)",
      "status": "met"
